"use client";

import { Lock, Key, Loader2, CheckCircle2, ArrowRight } from "lucide-react";
import { useSearchParams, useRouter } from "next/navigation";
import { useEffect, useState, Suspense } from "react";

function ResetPasswordContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const email = searchParams.get("email");

  const [otp, setOtp] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem("accessToken");
    if (token) {
      router.replace("/");
    }
    if (!email) {
      router.replace("/forgot-password");
    }
  }, [email, router]);

  const handleReset = async (e) => {
    e.preventDefault();

    if (!otp || !password) {
      setMessage({ type: "error", text: "Please fill in all fields" });
      return;
    }

    if (password.length < 8) {
      setMessage({
        type: "error",
        text: "Password must be at least 8 characters",
      });
      return;
    }

    try {
      setLoading(true);
      setMessage(null);

      const res = await fetch("http://localhost:5000/user/resetPassword", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email,
          otp,
          newPassword: password,
        }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.message);

      setMessage({
        type: "success",
        text: "Password updated! Redirecting to login...",
      });

      setTimeout(() => {
        router.push("/login");
      }, 2000);
    } catch (err) {
      setMessage({
        type: "error",
        text: err.message || "Reset failed. Please check your OTP.",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col justify-center items-center bg-[#F8FAFC] px-4">
      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-64 bg-gradient-to-b from-blue-50 to-transparent -z-10" />

      <div className="w-full max-w-[440px]">
        <div className="bg-white p-8 md:p-10 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100">
          <div className="flex flex-col items-center mb-8">
            <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-4 border border-blue-100">
              <Key className="w-8 h-8 text-blue-600" />
            </div>
            <h1 className="text-2xl font-black text-gray-900 tracking-tight italic">
              Reset Password
            </h1>
            <p className="text-gray-500 text-sm mt-2 text-center">
              Enter the code sent to <br />
              <span className="text-blue-600 font-bold">{email}</span>
            </p>
          </div>

          <form onSubmit={handleReset} className="space-y-5">
            {/* OTP Field */}
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-1">
                Verification Code (OTP)
              </label>
              <div className="relative group">
                <Key className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-blue-500 transition-colors" />
                <input
                  type="text"
                  placeholder="Enter 6-digit code"
                  className="w-full pl-12 pr-4 h-14 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:border-blue-500 focus:bg-white focus:ring-4 focus:ring-blue-500/5 transition-all text-gray-900 font-bold tracking-[0.2em]"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                />
              </div>
            </div>

            {/* Password Field */}
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-1">
                New Password
              </label>
              <div className="relative group">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-blue-500 transition-colors" />
                <input
                  type="password"
                  placeholder="••••••••"
                  className="w-full pl-12 pr-4 h-14 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:border-blue-500 focus:bg-white focus:ring-4 focus:ring-blue-500/5 transition-all text-gray-900 font-medium"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading || message?.type === "success"}
              className="group relative w-full bg-blue-600 h-14 text-white rounded-2xl font-bold text-lg hover:bg-blue-700 active:scale-[0.98] transition-all disabled:opacity-70 shadow-lg shadow-blue-200"
            >
              <div className="flex items-center justify-center gap-2">
                {loading ? (
                  <Loader2 className="w-5 h-5 animate-spin" />
                ) : message?.type === "success" ? (
                  <CheckCircle2 className="w-5 h-5" />
                ) : (
                  <span>Update Password</span>
                )}
              </div>
            </button>
          </form>

          {/* Alert Messages */}
          {message && (
            <div
              className={`mt-6 p-4 rounded-xl text-sm font-medium border flex items-start gap-3 animate-in fade-in slide-in-from-top-2 ${
                message.type === "error"
                  ? "bg-red-50 text-red-600 border-red-100"
                  : "bg-emerald-50 text-emerald-600 border-emerald-100"
              }`}
            >
              {message.type === "success" && (
                <CheckCircle2 className="w-5 h-5 shrink-0" />
              )}
              <p>{message.text}</p>
            </div>
          )}
        </div>

        <p className="mt-8 text-center text-xs text-gray-400 font-medium tracking-wide">
          Didn't get the code?{" "}
          <button className="text-blue-600 font-bold hover:underline">
            Resend OTP
          </button>
        </p>
      </div>
    </div>
  );
}

export default function ResetPasswordPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen flex items-center justify-center">
          Loading...
        </div>
      }
    >
      <ResetPasswordContent />
    </Suspense>
  );
}
